  ('social-worker-moex-02921', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '總結評估（summative evaluation）通常是針對已經完成之社會服務方案進行評估，據以研判方案的優缺點， 進行方案之延續或選擇，由於需要客觀的第三者進行，因此由外部評估較為適宜。請問「總結評估」應 該包含那些評估在內較完整？', '["結果評估（evaluation of outcome）與適切性評估（evaluation of adequacy）", "結果評估（evaluation of outcome）與成效評估（evaluation of effectiveness）", "適切性評估（evaluation of adequacy）與成效評估（evaluation of effectiveness）", "結果評估（evaluation of outcome）、適切性評估（evaluation of adequacy）及成效評估（evaluation of effectiveness）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02922', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Martin（2002）對於方案的生命週期模式的描述何者正確？', '["界定(cid:198)執行(cid:198)規劃(cid:198)結束(cid:198)評估", "界定(cid:198)規劃(cid:198)執行(cid:198)結束(cid:198)評估", "界定(cid:198)執行(cid:198)規劃(cid:198)評估(cid:198)結束", "界定(cid:198)規劃(cid:198)執行(cid:198)評估(cid:198)結束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02923', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一財團法人社會福利基金會聘用專職工作人員約 100 人，而大部分的專職員工是社會工作員。請問下 列那項工作不是該基金會董（監）事的主要職責？', '["修改捐助章程", "審查年度預算", "維繫基金會的使命", "督導社會工作實務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02924', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '臺中市某家醫院的志工已經有多名志工服務年資滿三年，且服務時數均超過 300 小時。請問該醫院的志 願服務業務承辦人得檢具相關文件向那一個機關為這些志工申請志願服務榮譽卡？', '["內政部社會司", "行政院衛生署", "臺中市政府衛生局", "臺中市政府社會局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02925', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據我國於民國95年通過的〈公益勸募條例〉，下列募款活動的描述中那一項符合〈公益勸募條例〉的 規定？', '["我國的任何公立或民間組織都可以從事募款活動", "辦理募款活動之前只要向主管機關報備即可", "辦理募款活動的期間最長為三個月", "勸募活動所得在新臺幣一千萬元以下者，辦理募款活動的必要支出為募款所得的百分之十五以內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02926', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列那一項活動是社會福利機構的社會行銷（social marketing）活動？', '["中秋節月餅義賣", "人口販運防制理念的宣導", "散發介紹機構宗旨與服務內容的機構簡介", "籌措方案經費的募款活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02927', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據中華民國建國一百年社會福利政策綱領所宣示，下列何者不是「新社會」的核心價值？', '["自由", "公平", "正義", "包容"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02928', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關女性主義理論對福利與公民權的主張，下列何者正確？', '["貧窮女性化的現象已然消失，主要原因是多數女性已能在就業市場中賺取薪資，取得獨立的社會保障 資格", "女性應該擁有獨立的公民權與社會權，不應被視為男性的依賴者，故養家薪資（family wage）是一種 父權的表現", "兩性的公民權與社會權內涵應該儘可能都一致，才是平等與正義的象徵", "女性主義學者認為福利國家應強化雙軌式系統設計，以提升對女性的經濟保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02929', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '目前內政部正在推動平民銀行實驗計畫，是透過鼓勵儲蓄、參與志願服務、參與教育訓練等策略來協助 經濟弱勢族群脫離貧窮。請問這是那種脫貧策略？', '["急難救助", "資產形成", "工作福利", "財稅福利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02930', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會政策與意識形態的敘述，下列何者錯誤？', '["新右派福利意識形態主要的政治體現是民營化，以1980年代的雷根主義與柴契爾主義為代表", "第三條路的意識形態主張為因應全球化風險，福利應該以社會投資為導向，強化依賴者的就業動機", "老左派的社會民主意識形態，在全球化的挑戰下，紛紛開始福利改革，向第三條路靠攏", "新右派與第三條路有許多共同特質，包括強調個人責任、國家效率、充分就業與結果平等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
